public void testNonPrimitiveFieldAnnotationTakesPrecedenceOverDefault() {
    Gson gson = new Gson();

    class Wrapper {
      @JsonAdapter(PartJsonFieldAnnotationAdapter.class)
      Integer value;

      Wrapper(Integer value) {
        this.value = value;
      }
    }

    String json = gson.toJson(new Wrapper(100));
    assertEquals("{\"value\":\"100\"}", json);
    Wrapper wrapper = gson.fromJson(json, Wrapper.class);
    assertEquals(Integer.valueOf(100), wrapper.value);
  }

public void testFieldWithoutAnnotationUsesDefaultAdapter() {
    Gson gson = new Gson();

    class SimpleClass {
      int value;

      SimpleClass(int value) {
        this.value = value;
      }
    }

    String json = gson.toJson(new SimpleClass(99));
    assertEquals("{\"value\":99}", json);
    SimpleClass obj = gson.fromJson(json, SimpleClass.class);
    assertEquals(99, obj.value);
  }

public void testNullValueWithPrimitiveAnnotation() {
    Gson gson = new Gson();

    class NullableWrapper {
      @JsonAdapter(PartJsonFieldAnnotationAdapter.class)
      Integer value;

      NullableWrapper(Integer value) {
        this.value = value;
      }
    }

    String json = gson.toJson(new NullableWrapper(null));
    assertEquals("{}", json);
    NullableWrapper wrapper = gson.fromJson("{\"value\":null}", NullableWrapper.class);
    assertNull(wrapper.value);
  }
